require_once __DIR__.'/../../config/auth.php';require_once __DIR__.'/../../config/database.php';require_once __DIR__.'/../../config/helper.php';require_admin();$pdo=db();$cats=$pdo?$pdo->query('SELECT id,nama FROM kategori_materi ORDER BY nama')->fetchAll():[];$errors=[];$data=['kategori_id'=>'','judul'=>'','ringkasan'=>'','konten'=>'','status'=>'publish'];
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();foreach($data as $k=>$v)$data[$k]=trim((string)($_POST[$k]??$v));if(!$pdo)$errors[]='Database belum terhubung.';if($data['judul']==='')$errors[]='Judul wajib diisi.';if($data['konten']==='')$errors[]='Konten materi wajib diisi.';if(!in_array($data['status'],['publish','draft'],true))$data['status']='draft';if(!$errors&&$pdo){$slug=slugify($data['judul']);$base=$slug;$i=2;$c=$pdo->prepare('SELECT id FROM materi WHERE slug=?');while(true){$c->execute([$slug]);if(!$c->fetch())break;$slug=$base.'-'.$i++;}$s=$pdo->prepare('INSERT INTO materi(kategori_id,judul,slug,ringkasan,konten,status,created_at) VALUES(?,?,?,?,?,?,NOW())');$s->execute([$data['kategori_id']!==''?(int)$data['kategori_id']:null,$data['judul'],$slug,$data['ringkasan'],$data['konten'],$data['status']]);log_activity($pdo,(int)current_user()['id'],'Menambahkan materi '.$data['judul']);flash('success','Materi berhasil ditambahkan.');redirect('admin/materi/index.php');}}
